{
  "executive_summary": "A food delivery platform architecture built around five bounded contexts — Order Lifecycle, Restaurant, Customer, Delivery Logistics, and Payments — connected via domain events through a message broker. The design prioritizes independent deployability of each context, an event-driven order state machine as the central coordination mechanism, and CQRS in the customer-facing read path for low-latency menu browsing. The architecture optimizes for the two hardest problems in this domain: real-time delivery matching/tracking and reliable order state transitions across multiple parties.",

  "architecture": {
    "components": [
      { "name": "API Gateway", "responsibility": "Single entry point for all clients (customer app, restaurant dashboard, driver app). Handles authentication, rate limiting, request routing, and protocol translation (REST/WebSocket).", "boundaries": "Stateless edge layer. No business logic. Routes to downstream services only." },
      { "name": "Customer Service", "responsibility": "Customer profiles, addresses, favorites, search/browse experience. Owns the customer-facing read model for restaurant menus (CQRS projection).", "boundaries": "Owns Customer aggregate. Consumes menu data via events from Restaurant Service. Does NOT own orders or payments." },
      { "name": "Restaurant Service", "responsibility": "Restaurant onboarding, menu management, availability/hours, menu item pricing, prep time estimates. Publishes menu change events.", "boundaries": "Owns Restaurant and Menu aggregates. Does not process orders — emits events consumed by Order Service." },
      { "name": "Order Service", "responsibility": "Central order lifecycle management. Implements the order state machine (placed → confirmed → preparing → ready → picked_up → delivered). Coordinates between restaurant confirmation, payment authorization, and driver assignment.", "boundaries": "Owns Order aggregate. Orchestrates via a saga/process manager pattern. Does NOT hold payment or delivery state — delegates to those services." },
      { "name": "Delivery Service", "responsibility": "Driver profiles, real-time location tracking, driver-order matching algorithm, route optimization, ETA calculation. Manages driver availability state machine (offline → available → assigned → en_route → delivering).", "boundaries": "Owns Driver and Delivery aggregates. Consumes order-ready events. Publishes delivery status events." },
      { "name": "Payment Service", "responsibility": "Payment method management, authorization, capture, refunds, restaurant payouts, driver earnings. Integrates with external payment processor (Stripe/Adyen).", "boundaries": "Owns PaymentTransaction aggregate. Isolated from all business logic — acts as a financial ledger. Anti-corruption layer wraps external payment gateway." },
      { "name": "Notification Service", "responsibility": "Push notifications, SMS, email across all actors. Consumes domain events and applies notification rules/preferences.", "boundaries": "Generic subdomain. No business state. Purely reactive — triggered by domain events." },
      { "name": "Search & Discovery Service", "responsibility": "Restaurant search, filtering, ranking, personalized recommendations. Maintains a denormalized search index (Elasticsearch) projected from Restaurant and Customer events.", "boundaries": "Read-only projection. No writes back to source systems." },
      { "name": "Rating & Review Service", "responsibility": "Post-delivery ratings for restaurants, drivers, and customers. Fraud detection on reviews.", "boundaries": "Owns Rating aggregate. Publishes rating events consumed by Restaurant and Delivery services for score updates." }
    ],
    "interfaces": [
      { "from": "API Gateway", "to": "All Services", "contract": "REST/gRPC with OpenAPI specs. WebSocket upgrade for real-time tracking.", "coupling_type": "loose — gateway only knows routes, not internals" },
      { "from": "Customer Service", "to": "Order Service", "contract": "PlaceOrder command via synchronous API call (needs immediate response with order ID)", "coupling_type": "synchronous command — acceptable because order placement is a critical user-facing flow" },
      { "from": "Order Service", "to": "Restaurant Service", "contract": "OrderPlaced domain event → Restaurant confirms/rejects asynchronously → OrderConfirmed/OrderRejected event", "coupling_type": "async event-driven via message broker" },
      { "from": "Order Service", "to": "Payment Service", "contract": "AuthorizePayment command (sync for UX) on order placement. CapturePayment event on delivery completion.", "coupling_type": "sync for auth, async for capture — split by UX requirement" },
      { "from": "Order Service", "to": "Delivery Service", "contract": "OrderReadyForPickup event triggers driver matching. Delivery Service publishes DriverAssigned, PickedUp, Delivered events.", "coupling_type": "fully async event-driven" },
      { "from": "Delivery Service", "to": "Customer Service", "contract": "DriverLocationUpdated events streamed via WebSocket through gateway for real-time tracking", "coupling_type": "async streaming — fire and forget" },
      { "from": "Restaurant Service", "to": "Search & Discovery Service", "contract": "MenuUpdated, RestaurantAvailabilityChanged events projected into search index", "coupling_type": "async eventual consistency" },
      { "from": "All Services", "to": "Notification Service", "contract": "Domain events consumed and mapped to notification templates per user preferences", "coupling_type": "fully decoupled — notification service is a pure consumer" }
    ],
    "data_flow": "1. Customer browses restaurants via Search & Discovery (read-optimized projection). 2. Customer places order → API Gateway → Customer Service → Order Service (sync). 3. Order Service authorizes payment (sync) → publishes OrderPlaced event. 4. Restaurant Service consumes OrderPlaced, restaurant confirms → OrderConfirmed event. 5. Order Service updates state, emits OrderConfirmed. Kitchen prepares food, restaurant marks ready → OrderReadyForPickup event. 6. Delivery Service matches driver, publishes DriverAssigned. Driver navigates to restaurant, picks up → PickedUp event. 7. Driver delivers → Delivered event. 8. Order Service captures payment, triggers payout calculation. 9. Rating & Review Service prompts for feedback. Throughout: Notification Service reacts to all state transitions. Delivery Service streams driver GPS to customer via WebSocket.",
    "patterns_used": [
      { "pattern": "Event-Driven Architecture", "rationale": "The three-party coordination (customer, restaurant, driver) is inherently asynchronous. Events decouple these actors and allow each to progress independently. Critical for handling the 'restaurant is slow' or 'driver cancels' scenarios without blocking." },
      { "pattern": "Saga / Process Manager", "rationale": "Order lifecycle spans multiple services (payment, restaurant, delivery). A saga in Order Service orchestrates compensating actions — e.g., if restaurant rejects after payment auth, trigger refund. Prevents distributed transaction complexity." },
      { "pattern": "CQRS", "rationale": "Menu browsing (read-heavy, needs sub-100ms) has completely different access patterns than menu management (write, infrequent). Separate read projections in Customer/Search services allow independent scaling and optimization." },
      { "pattern": "Anti-Corruption Layer", "rationale": "Payment gateway (Stripe/Adyen) has its own model. ACL in Payment Service translates between our domain language (authorize, capture, refund) and gateway-specific API, preventing vendor lock-in." },
      { "pattern": "State Machine", "rationale": "Both Order and Delivery have well-defined state transitions with strict invariants (e.g., can't pick up before confirmed). Explicit state machines make invalid states unrepresentable and simplify debugging." },
      { "pattern": "Strangler Fig (for evolution)", "rationale": "Initial deployment can be a modular monolith with these contexts as modules. Extract to services only when scaling demands it. Avoids premature distributed systems complexity." }
    ]
  },

  "domain_model": {
    "bounded_contexts": [
      {
        "name": "Order Management",
        "classification": "core",
        "aggregates": [
          "Order (root: orderId, contains OrderItems, tracks state machine, refs customerId/restaurantId/driverId as IDs only)",
          "OrderSaga (process manager tracking compensation state across payment/restaurant/delivery)"
        ]
      },
      {
        "name": "Restaurant",
        "classification": "core",
        "aggregates": [
          "Restaurant (root: restaurantId, contains OperatingHours, Location, ServiceArea)",
          "Menu (root: menuId, contains MenuSections → MenuItems with pricing, availability, modifiers)"
        ]
      },
      {
        "name": "Delivery & Logistics",
        "classification": "core",
        "aggregates": [
          "Driver (root: driverId, contains VehicleInfo, state machine: offline/available/assigned/en_route/delivering)",
          "Delivery (root: deliveryId, contains Route, ETAs, pickup/dropoff locations, refs orderId/driverId)"
        ]
      },
      {
        "name": "Customer",
        "classification": "supporting",
        "aggregates": [
          "Customer (root: customerId, contains SavedAddresses, Preferences, FavoriteRestaurants)"
        ]
      },
      {
        "name": "Payments & Billing",
        "classification": "supporting",
        "aggregates": [
          "PaymentTransaction (root: transactionId, tracks auth/capture/refund lifecycle, refs orderId)",
          "Payout (root: payoutId, restaurant/driver earnings calculation and disbursement)"
        ]
      },
      {
        "name": "Identity & Access",
        "classification": "generic",
        "aggregates": [
          "User (root: userId, authentication credentials, roles: customer/restaurant_admin/driver/platform_admin)"
        ]
      },
      {
        "name": "Notifications",
        "classification": "generic",
        "aggregates": [
          "NotificationPreference (root: userId, channel preferences per event type)",
          "NotificationLog (append-only delivery tracking)"
        ]
      },
      {
        "name": "Search & Discovery",
        "classification": "supporting",
        "aggregates": [
          "SearchIndex (denormalized read model — not a true aggregate, projection only)"
        ]
      },
      {
        "name": "Ratings",
        "classification": "supporting",
        "aggregates": [
          "Rating (root: ratingId, contains score, review text, refs orderId, raterId, targetId, targetType)"
        ]
      }
    ],
    "context_map": [
      { "upstream": "Order Management", "downstream": "Delivery & Logistics", "relationship": "Customer-Supplier — Order dictates what Delivery must fulfill, but Delivery owns how" },
      { "upstream": "Order Management", "downstream": "Payments & Billing", "relationship": "Customer-Supplier — Order triggers payment commands, Payment Service conforms to Order's lifecycle events" },
      { "upstream": "Restaurant", "downstream": "Order Management", "relationship": "Customer-Supplier — Restaurant confirms/rejects orders and signals readiness; Order conforms to restaurant's availability model" },
      { "upstream": "Restaurant", "downstream": "Search & Discovery", "relationship": "Published Language — Restaurant publishes menu/availability events; Search consumes and projects into its own model" },
      { "upstream": "Payments & Billing", "downstream": "External Payment Gateway", "relationship": "Anti-Corruption Layer — ACL wraps Stripe/Adyen to prevent external model leaking into domain" },
      { "upstream": "Order Management", "downstream": "Notifications", "relationship": "Open Host Service — Order publishes standardized events; Notifications is a conformist consumer" },
      { "upstream": "Delivery & Logistics", "downstream": "Customer", "relationship": "Published Language — Delivery publishes location streams; Customer app consumes for real-time tracking" },
      { "upstream": "Order Management", "downstream": "Ratings", "relationship": "Customer-Supplier — Ratings triggered by OrderDelivered event; Rating context conforms to Order's completed state" }
    ]
  },

  "trade_offs": [
    {
      "decision": "Event-driven async coordination over synchronous orchestration",
      "gains": "Resilience (restaurant going offline doesn't block driver assignment), independent scalability, natural fit for the multi-party async nature of food delivery",
      "sacrifices": "Eventual consistency complexity, harder debugging (distributed tracing required), potential event ordering issues",
      "alternatives_considered": ["Synchronous orchestration via API calls — simpler but creates tight coupling and cascade failures", "Choreography-only (no orchestrator) — too hard to reason about order lifecycle with 8+ states"]
    },
    {
      "decision": "Saga pattern in Order Service (orchestration) over pure choreography",
      "gains": "Centralized view of order lifecycle, easier to implement compensating transactions (refunds on rejection), clearer failure handling",
      "sacrifices": "Order Service becomes a coordination bottleneck, slightly more coupling than pure choreography",
      "alternatives_considered": ["Pure choreography — each service reacts to events independently. Rejected because order lifecycle has too many failure modes requiring coordinated compensation"]
    },
    {
      "decision": "Start as modular monolith, extract services when needed",
      "gains": "Faster initial delivery, no distributed systems overhead at launch, easier refactoring while domain model is still being discovered",
      "sacrifices": "Must enforce module boundaries with discipline (no cross-module DB queries). Risk of coupling if boundaries aren't maintained",
      "alternatives_considered": ["Microservices from day one — rejected as premature for a new platform with evolving domain understanding"]
    },
    {
      "decision": "CQRS for menu browsing (separate read model) over shared database reads",
      "gains": "Menu browsing at massive scale without impacting restaurant admin writes, can optimize read model shape for mobile app needs, sub-100ms response times",
      "sacrifices": "Stale data (eventual consistency — menu price could be seconds behind), additional infrastructure (projection pipeline)",
      "alternatives_considered": ["Direct DB reads with caching — simpler but couples read scaling to write database capacity"]
    },
    {
      "decision": "WebSocket for real-time driver tracking over polling",
      "gains": "True real-time UX (1-2 second location updates), lower server load than polling, better mobile battery life",
      "sacrifices": "WebSocket infrastructure complexity, connection management at scale, harder to load balance",
      "alternatives_considered": ["Server-Sent Events — simpler but unidirectional, can't easily support driver-to-server updates", "Long polling — too much overhead at scale"]
    }
  ],

  "flexibility_points": [
    { "area": "Payment Gateway", "evolution_path": "ACL around payment provider means swapping Stripe for Adyen (or adding both) requires changes only in the Payment Service's infrastructure layer. Domain model stays untouched." },
    { "area": "Driver Matching Algorithm", "evolution_path": "Matching logic is isolated in Delivery Service behind a DriverMatcher interface. Can evolve from simple nearest-driver to ML-based optimization without touching other services." },
    { "area": "Search & Ranking", "evolution_path": "Search is a read-only projection — can swap Elasticsearch for Typesense, add ML-ranked results, or implement personalization without affecting source data." },
    { "area": "Notification Channels", "evolution_path": "Adding new channels (WhatsApp, in-app chat) only requires new adapters in Notification Service. No changes to event producers." },
    { "area": "Pricing & Promotions", "evolution_path": "Currently embedded in Order Service, but designed as a distinct module. Can extract to a dedicated Pricing Service when surge pricing, dynamic delivery fees, or complex promo rules warrant it." },
    { "area": "Service Extraction", "evolution_path": "Modular monolith start means any bounded context can be extracted to a standalone service when it hits scaling limits. Message broker integration points are already defined." }
  ],

  "rigidity_points": [
    { "area": "Order State Machine", "reason": "The order state transitions (placed→confirmed→preparing→ready→picked_up→delivered) and their invariants must be extremely rigid. Bugs here cause financial loss (double charges, missed payouts) and customer trust damage. This is intentional rigidity." },
    { "area": "Payment Transaction Integrity", "reason": "Authorization → capture → refund flow must be ACID-compliant within the Payment Service boundary. No eventual consistency for money movement. Idempotency keys mandatory on all payment operations." },
    { "area": "Event Schema Contracts", "reason": "Published domain events are contracts between contexts. Schema changes require versioning (e.g., OrderPlacedV2). Breaking changes need coordinated migration. This coupling is the cost of decoupling everything else." },
    { "area": "Driver Location Ingestion Pipeline", "reason": "Must handle high-frequency GPS updates (every 3-5 seconds per active driver) with minimal latency. This pipeline's throughput characteristics constrain technology choices (needs stream processing, not request-response)." }
  ],

  "risks": [
    { "risk": "Order saga complexity — compensating transactions across payment, restaurant, and delivery can produce edge cases (e.g., restaurant confirms then closes, payment captured but driver unavailable)", "severity": "critical", "mitigation": "Exhaustive state machine modeling with explicit handling for every failure transition. Dead letter queue for unhandled events. Manual resolution dashboard for operations team." },
    { "risk": "Real-time tracking at scale — thousands of concurrent WebSocket connections with 3-second GPS updates creates significant infrastructure load", "severity": "high", "mitigation": "Use a dedicated real-time layer (Redis Pub/Sub or dedicated WebSocket service). Geospatial indexing for efficient proximity queries. Connection pooling and graceful degradation to polling under load." },
    { "risk": "Eventual consistency causing customer-visible stale data — customer sees menu item that restaurant just removed, places order, order gets rejected", "severity": "high", "mitigation": "Optimistic UI with server-side validation at order placement. Clear UX for 'item no longer available' after placement. Keep projection lag under 5 seconds with monitoring/alerting." },
    { "risk": "Driver matching fairness and efficiency — naive nearest-driver matching leads to unfair earnings distribution and suboptimal overall throughput", "severity": "medium", "mitigation": "Start with simple nearest-available algorithm behind an interface. Instrument with metrics (acceptance rate, delivery time, driver earnings distribution). Evolve to batch matching optimization when data supports it." },
    { "risk": "Modular monolith discipline erosion — developers bypass module boundaries with direct database queries or shared mutable state", "severity": "medium", "mitigation": "Enforce module boundaries with ArchUnit-style tests. Each module owns its database schema (separate schemas in same DB). Code review gates on cross-module imports." },
    { "risk": "Payment failure during high-traffic periods (lunch rush) causing order placement failures", "severity": "high", "mitigation": "Circuit breaker on payment gateway calls. Queue-based payment processing for non-blocking authorization where UX allows. Multi-provider failover via ACL." }
  ],

  "implementation_guidance": {
    "recommended_approach": "Phase 1: Build as a modular monolith with clearly separated bounded contexts sharing a single deployment unit but isolated database schemas. Implement the Order state machine, Restaurant menu management, basic Customer ordering flow, and Payment integration (Stripe). Use an in-process event bus initially. Phase 2: Add Delivery context with simple nearest-driver matching and real-time tracking. Phase 3: Extract Search & Discovery to a separate service with Elasticsearch. Phase 4: Extract high-scale contexts (Delivery, Order) to independent services connected via message broker (Kafka/RabbitMQ) when traffic warrants it.",
    "files_to_create_or_modify": [
      "src/order/domain/Order.ts — Order aggregate with state machine",
      "src/order/domain/OrderSaga.ts — Saga/process manager for cross-service coordination",
      "src/order/domain/events/ — OrderPlaced, OrderConfirmed, OrderRejected, OrderReady, OrderDelivered",
      "src/restaurant/domain/Restaurant.ts — Restaurant aggregate",
      "src/restaurant/domain/Menu.ts — Menu aggregate with items, sections, modifiers",
      "src/delivery/domain/Driver.ts — Driver aggregate with availability state machine",
      "src/delivery/domain/Delivery.ts — Delivery aggregate with route and ETA",
      "src/delivery/application/DriverMatcher.ts — Interface for matching algorithm",
      "src/customer/domain/Customer.ts — Customer aggregate",
      "src/payment/domain/PaymentTransaction.ts — Payment aggregate with auth/capture lifecycle",
      "src/payment/infrastructure/StripeAdapter.ts — ACL wrapping Stripe SDK",
      "src/shared/domain/EventBus.ts — In-process event bus (extract to broker later)",
      "src/shared/domain/DomainEvent.ts — Base event type with versioning support",
      "infrastructure/docker-compose.yml — PostgreSQL, Redis, Elasticsearch",
      "docs/adr/001-modular-monolith-first.md — Architecture decision record",
      "docs/adr/002-order-state-machine.md — State machine design rationale",
      "docs/adr/003-event-driven-coordination.md — Event-driven approach rationale"
    ],
    "patterns_to_follow": "Each bounded context follows hexagonal architecture internally: domain layer (aggregates, events, repository interfaces) → application layer (use cases, saga) → infrastructure layer (DB adapters, external API adapters, event bus adapters). All cross-context communication goes through the event bus — never import from another context's domain layer. Use repository pattern per aggregate root. Value objects for all non-identity concepts (Money, Address, GeoLocation, TimeWindow).",
    "pitfalls_to_avoid": [
      "Do NOT create a shared 'common' or 'core' library with business types — this becomes a coupling magnet. Only truly generic types (Result, DomainEvent base) belong in shared.",
      "Do NOT use distributed transactions (2PC) across services — use sagas with compensating actions instead.",
      "Do NOT store driver locations in a relational database — use Redis with geospatial indexes (GEOADD/GEORADIUS) for real-time location queries.",
      "Do NOT let the Order aggregate grow to contain restaurant details, driver details, or payment details — reference by ID only. Fetch what you need via read models.",
      "Do NOT skip idempotency keys on payment operations — network retries WILL cause duplicate charges without them.",
      "Do NOT model delivery fee calculation in the Delivery context — it belongs in Order/Pricing. Delivery context only handles logistics.",
      "Do NOT expose internal domain events directly as API contracts — create separate DTOs/API events to allow internal model evolution."
    ]
  },

  "escalations": [],

  "confidence": {
    "level": 82,
    "high_confidence_areas": [
      "Bounded context boundaries — restaurant, order, delivery, payment are well-established separations validated by every major food delivery platform",
      "Event-driven coordination — the three-party async nature of food delivery makes this the natural architectural style",
      "Order state machine as the central coordination mechanism",
      "CQRS for menu browsing — read/write asymmetry is extreme in this domain",
      "ACL around payment gateway — standard and well-proven"
    ],
    "low_confidence_areas": [
      "Exact boundary between Order and a potential Pricing/Promotions context — depends on business complexity that hasn't been specified",
      "Driver matching algorithm requirements — simple nearest-driver vs. batch optimization depends on market density and business rules not yet defined",
      "Scale requirements — modular monolith recommendation assumes sub-10K concurrent orders; if this is a mega-scale platform, microservices-first may be warranted",
      "Multi-restaurant orders (cart from multiple restaurants) — not addressed, would significantly complicate the Order aggregate if required"
    ],
    "assumptions": [
      "Single-restaurant orders only (one order = one restaurant)",
      "Standard three-party model (customer, restaurant, driver) — no ghost kitchens or platform-owned fulfillment",
      "Moderate initial scale (city-level launch, not global day one)",
      "Mobile-first customer experience with restaurant web dashboard",
      "Third-party payment processing (not building our own payment infrastructure)",
      "Drivers are independent contractors, not employees (affects Driver aggregate design)"
    ]
  }
}
